{
}

Method.Source:
/// <summary>
/// write shipment lines for outbound orders
/// </summary>
/// <param name = "_sourceLine">Common _sourceLine</param>
private void writeShipLineOutETG(Common _sourceLine)
{
    shipLine.ShipId = shipId;
    shipLine.ShipContainerId = shipContainerId;
    shipLine.ShipFolioId = shipFolioId;
    shipLine.ShipPosition = position;
    shipLine.ShipMeasurement = measurement;
    shipLine.ShipMeasurementUnit = measurementUnit;
    shipLine.ShipNoOfCartons = cartons;

    if (!delayShipLineInsert)
    {
        shipLine.insert();
    }
    else
    {
        if (!this.validateShipLine(shipLine, _sourceLine))
        {
            throw error("@SYS18447");
        }
    }
}
